import React, { useState, useEffect } from 'react';
import { X, ChevronRight, ChevronLeft, Sparkles, Target, MessageSquare, LayoutDashboard, Settings } from 'lucide-react';

interface TourStep {
    targetId: string;
    title: string;
    content: string;
    icon: React.ReactNode;
    position: 'right' | 'left' | 'top' | 'bottom';
}

const OnboardingTour: React.FC = () => {
    const [isVisible, setIsVisible] = useState(false);
    const [currentStepIndex, setCurrentStepIndex] = useState(0);
    const [spotlightStyles, setSpotlightStyles] = useState<React.CSSProperties>({});

    const steps: TourStep[] = [
        {
            targetId: '', // Neutral start
            title: "Bienvenue sur Élite CRM",
            content: "Laissez-moi vous montrer comment transformer vos prospects en étudiants inscrits en quelques clics.",
            icon: <Sparkles size={24} color="var(--primary)" />,
            position: 'bottom'
        },
        {
            targetId: 'tour-dashboard',
            title: "Tableau de Bord",
            content: "C'est ici que vous suivez vos performances globales et l'activité récente de votre équipe.",
            icon: <LayoutDashboard size={24} color="var(--primary)" />,
            position: 'right'
        },
        {
            targetId: 'tour-campaigns',
            title: "Gestion des Campagnes",
            content: "Ici, vous importez vos leads (Excel/CSV) et gérez vos sources de trafic (TikTok, FB, Salons).",
            icon: <Target size={24} color="var(--primary)" />,
            position: 'right'
        },
        {
            targetId: 'tour-messaging',
            title: "Centre de Messagerie",
            content: "Automatisez vos relances WhatsApp et envoyez des messages personnalisés à vos groupes de prospects.",
            icon: <MessageSquare size={24} color="var(--primary)" />,
            position: 'right'
        },
        {
            targetId: 'tour-settings',
            title: "Configuration du Workspace",
            content: "Personnalisez votre CRM, gérez vos conseillers et connectez vos outils externes.",
            icon: <Settings size={24} color="var(--primary)" />,
            position: 'right'
        }
    ];

    useEffect(() => {
        const hasSeenTour = localStorage.getItem('elite_crm_tour_seen');
        if (!hasSeenTour) {
            setTimeout(() => setIsVisible(true), 1500);
        }
    }, []);

    useEffect(() => {
        if (!isVisible || currentStepIndex === 0) {
            setSpotlightStyles({ opacity: 0, pointerEvents: 'none' });
            return;
        }

        const step = steps[currentStepIndex];
        const element = document.getElementById(step.targetId);

        if (element) {
            const rect = element.getBoundingClientRect();
            setSpotlightStyles({
                top: rect.top - 8,
                left: rect.left - 8,
                width: rect.width + 16,
                height: rect.height + 16,
                opacity: 1,
                boxShadow: '0 0 0 9999px rgba(0, 0, 0, 0.75), 0 0 15px var(--primary-glow)',
                borderRadius: '12px'
            });

            // Auto-scroll to element if needed
            element.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [currentStepIndex, isVisible]);

    const handleNext = () => {
        if (currentStepIndex < steps.length - 1) {
            setCurrentStepIndex(currentStepIndex + 1);
        } else {
            completeTour();
        }
    };

    const handlePrev = () => {
        if (currentStepIndex > 0) {
            setCurrentStepIndex(currentStepIndex - 1);
        }
    };

    const completeTour = () => {
        setIsVisible(false);
        localStorage.setItem('elite_crm_tour_seen', 'true');
    };

    if (!isVisible) return null;

    const currentStep = steps[currentStepIndex];

    return (
        <div style={{ position: 'fixed', inset: 0, zIndex: 9999, pointerEvents: 'none' }}>
            {/* Backdrop Spotlight */}
            <div style={{
                position: 'absolute',
                transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                border: '2px solid var(--primary)',
                ...spotlightStyles
            }} />

            {/* Tooltip */}
            <div style={{
                position: 'absolute',
                pointerEvents: 'auto',
                top: currentStep.targetId ? (document.getElementById(currentStep.targetId)?.getBoundingClientRect().top || 50) : '50%',
                left: currentStep.targetId ? (document.getElementById(currentStep.targetId)?.getBoundingClientRect().right || 0) + 40 : '50%',
                transform: currentStep.targetId ? 'translateY(-50%)' : 'translate(-50%, -50%)',
                width: '320px',
                background: 'rgba(23, 23, 35, 0.9)',
                backdropFilter: 'blur(20px)',
                border: '1px solid var(--border)',
                borderRadius: '20px',
                padding: '1.5rem',
                boxShadow: '0 20px 40px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.05)',
                transition: 'all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)'
            }}>
                <button
                    onClick={completeTour}
                    style={{ position: 'absolute', top: '1rem', right: '1rem', background: 'transparent', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' }}
                >
                    <X size={18} />
                </button>

                <div style={{ display: 'flex', gap: '1rem', marginBottom: '1rem' }}>
                    <div style={{
                        width: '48px',
                        height: '48px',
                        borderRadius: '12px',
                        background: 'rgba(99, 102, 241, 0.1)',
                        display: 'grid',
                        placeItems: 'center'
                    }}>
                        {currentStep.icon}
                    </div>
                    <div>
                        <h4 style={{ fontSize: '1.125rem', fontWeight: 700, color: 'white', marginBottom: '0.25rem' }}>{currentStep.title}</h4>
                        <div style={{ fontSize: '0.75rem', color: 'var(--primary)', fontWeight: 600 }}>Étape {currentStepIndex + 1} sur {steps.length}</div>
                    </div>
                </div>

                <p style={{ fontSize: '0.925rem', color: 'var(--text-muted)', lineHeight: '1.6', marginBottom: '1.5rem' }}>
                    {currentStep.content}
                </p>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <button
                        onClick={handlePrev}
                        disabled={currentStepIndex === 0}
                        style={{
                            background: 'transparent',
                            border: 'none',
                            color: currentStepIndex === 0 ? 'transparent' : 'var(--text-muted)',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '0.5rem',
                            fontSize: '0.875rem'
                        }}
                    >
                        <ChevronLeft size={16} /> Précédent
                    </button>

                    <button
                        onClick={handleNext}
                        className="btn btn-primary"
                        style={{ padding: '0.5rem 1.25rem', fontSize: '0.875rem' }}
                    >
                        {currentStepIndex === steps.length - 1 ? "C'est parti !" : "Suivant"} <ChevronRight size={16} />
                    </button>
                </div>

                {/* Arrow Pointer */}
                {currentStep.targetId && (
                    <div style={{
                        position: 'absolute',
                        left: '-8px',
                        top: '50%',
                        transform: 'translateY(-50%) rotate(45deg)',
                        width: '16px',
                        height: '16px',
                        background: 'rgba(23, 23, 35, 0.9)',
                        borderLeft: '1px solid var(--border)',
                        borderBottom: '1px solid var(--border)'
                    }} />
                )}
            </div>
        </div>
    );
};

export default OnboardingTour;

import React, { createContext, useContext, useState, type ReactNode } from 'react';
import { AlertCircle, CheckCircle2, XCircle, Info, X } from 'lucide-react';

type PopupType = 'alert' | 'confirm' | 'prompt';
type Severity = 'info' | 'success' | 'warning' | 'error';

interface PopupOptions {
    title: string;
    message: string;
    type?: PopupType;
    severity?: Severity;
    defaultValue?: string;
    confirmText?: string;
    cancelText?: string;
}

interface PopupContextType {
    showAlert: (title: string, message: string, severity?: Severity) => Promise<void>;
    showConfirm: (title: string, message: string, severity?: Severity) => Promise<boolean>;
    showPrompt: (title: string, message: string, defaultValue?: string, severity?: Severity) => Promise<string | null>;
}

const PopupContext = createContext<PopupContextType | undefined>(undefined);

export const usePopup = () => {
    const context = useContext(PopupContext);
    if (!context) throw new Error('usePopup must be used within a PopupProvider');
    return context;
};

export const PopupProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [options, setOptions] = useState<PopupOptions | null>(null);
    const [promptValue, setPromptValue] = useState('');
    const [resolvePromise, setResolvePromise] = useState<((value: any) => void) | null>(null);

    const show = (opts: PopupOptions) => {
        setOptions(opts);
        setPromptValue(opts.defaultValue || '');
        setIsOpen(true);
        return new Promise<any>((resolve) => {
            setResolvePromise(() => resolve);
        });
    };

    const handleConfirm = () => {
        if (!resolvePromise) return;
        setIsOpen(false);
        if (options?.type === 'prompt') resolvePromise(promptValue);
        else if (options?.type === 'confirm') resolvePromise(true);
        else resolvePromise(undefined);
    };

    const handleCancel = () => {
        if (!resolvePromise) return;
        setIsOpen(false);
        if (options?.type === 'prompt') resolvePromise(null);
        else if (options?.type === 'confirm') resolvePromise(false);
        else resolvePromise(undefined);
    };

    const showAlert = (title: string, message: string, severity: Severity = 'info') =>
        show({ title, message, type: 'alert', severity });

    const showConfirm = (title: string, message: string, severity: Severity = 'warning') =>
        show({ title, message, type: 'confirm', severity });

    const showPrompt = (title: string, message: string, defaultValue = '', severity: Severity = 'info') =>
        show({ title, message, type: 'prompt', defaultValue, severity });

    return (
        <PopupContext.Provider value={{ showAlert, showConfirm, showPrompt }}>
            {children}
            {isOpen && options && (
                <div className="popup-overlay animate-fade">
                    <div className="popup-card glassmorphism animate-scale">
                        <div className="popup-header">
                            <div className={`popup-icon-wrapper ${options.severity || 'info'}`}>
                                {options.severity === 'success' && <CheckCircle2 size={24} />}
                                {options.severity === 'error' && <XCircle size={24} />}
                                {options.severity === 'warning' && <AlertCircle size={24} />}
                                {options.severity === 'info' && <Info size={24} />}
                            </div>
                            <button className="popup-close" onClick={handleCancel}>
                                <X size={20} />
                            </button>
                        </div>

                        <div className="popup-content">
                            <h3>{options.title}</h3>
                            <p>{options.message}</p>

                            {options.type === 'prompt' && (
                                <div className="input-wrapper" style={{ marginTop: '1.25rem' }}>
                                    <input
                                        type="text"
                                        value={promptValue}
                                        onChange={(e) => setPromptValue(e.target.value)}
                                        autoFocus
                                        className="popup-input"
                                        placeholder="Saisissez ici..."
                                        onKeyDown={(e) => e.key === 'Enter' && handleConfirm()}
                                    />
                                </div>
                            )}
                        </div>

                        <div className="popup-footer">
                            {(options.type === 'confirm' || options.type === 'prompt') && (
                                <button className="btn btn-ghost" onClick={handleCancel}>
                                    {options.cancelText || 'Annuler'}
                                </button>
                            )}
                            <button
                                className={`btn ${options.severity === 'error' ? 'btn-danger' : 'btn-primary'}`}
                                onClick={handleConfirm}
                            >
                                {options.confirmText || (options.type === 'alert' ? 'D\'accord' : 'Confirmer')}
                            </button>
                        </div>
                    </div>

                    <style>{`
                        .popup-overlay {
                            position: fixed;
                            top: 0;
                            left: 0;
                            right: 0;
                            bottom: 0;
                            background: rgba(0, 0, 0, 0.7);
                            backdrop-filter: blur(4px);
                            display: grid;
                            place-items: center;
                            z-index: 9999;
                            padding: 1.5rem;
                        }
                        .popup-card {
                            width: 100%;
                            max-width: 400px;
                            border-radius: 20px;
                            padding: 1.5rem;
                            border: 1px solid rgba(255, 255, 255, 0.1);
                        }
                        .popup-header {
                            display: flex;
                            justify-content: space-between;
                            align-items: flex-start;
                            margin-bottom: 1.25rem;
                        }
                        .popup-icon-wrapper {
                            width: 48px;
                            height: 48px;
                            border-radius: 12px;
                            display: grid;
                            place-items: center;
                        }
                        .popup-icon-wrapper.info { background: rgba(99, 102, 241, 0.1); color: var(--primary); }
                        .popup-icon-wrapper.success { background: rgba(16, 185, 129, 0.1); color: var(--success); }
                        .popup-icon-wrapper.warning { background: rgba(245, 158, 11, 0.1); color: var(--warning); }
                        .popup-icon-wrapper.error { background: rgba(239, 68, 68, 0.1); color: var(--danger); }

                        .popup-close {
                            background: transparent;
                            border: none;
                            color: var(--text-muted);
                            cursor: pointer;
                            padding: 4px;
                            border-radius: 50%;
                            transition: all 0.2s;
                        }
                        .popup-close:hover { background: rgba(255,255,255,0.05); color: white; }

                        .popup-content h3 {
                            font-size: 1.25rem;
                            font-weight: 700;
                            margin-bottom: 0.5rem;
                            color: white;
                        }
                        .popup-content p {
                            font-size: 0.9375rem;
                            color: var(--text-muted);
                            line-height: 1.5;
                        }
                        .popup-input {
                            width: 100%;
                            background: rgba(255,255,255,0.03);
                            border: 1px solid var(--border);
                            border-radius: 10px;
                            padding: 0.75rem 1rem;
                            color: white;
                            font-size: 0.9375rem;
                        }
                        .popup-input:focus {
                            outline: none;
                            border-color: var(--primary);
                            background: rgba(255,255,255,0.05);
                        }
                        .popup-footer {
                            margin-top: 2rem;
                            display: flex;
                            justify-content: flex-end;
                            gap: 0.75rem;
                        }
                        .btn-ghost {
                            background: transparent;
                            color: var(--text-muted);
                        }
                        .btn-ghost:hover {
                            background: rgba(255,255,255,0.05);
                            color: white;
                        }
                        .btn-danger {
                            background: var(--danger);
                            color: white;
                        }

                        .animate-fade { animation: fadeIn 0.2s ease-out; }
                        .animate-scale { animation: scaleIn 0.2s ease-out; }
                        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
                        @keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
                    `}</style>
                </div>
            )}
        </PopupContext.Provider>
    );
};

import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Building2, Users, Mail, Lock, Plus, Trash, CheckCircle2, Loader2, Sparkles, AlertCircle } from 'lucide-react';
import { useToast } from './Toast';

interface Commercial {
    name: string;
    email: string;
}

const Provisioner: React.FC = () => {
    const { addToast } = useToast();
    const [isLoading, setIsLoading] = useState(false);
    const [isSuccess, setIsSuccess] = useState(false);

    // Form states
    const [orgName, setOrgName] = useState('');
    const [adminName, setAdminName] = useState('');
    const [adminEmail, setAdminEmail] = useState('');
    const [adminPassword, setAdminPassword] = useState('');
    const [commercials, setCommercials] = useState<Commercial[]>([{ name: '', email: '' }]);

    const addCommercial = () => {
        setCommercials([...commercials, { name: '', email: '' }]);
    };

    const removeCommercial = (index: number) => {
        setCommercials(commercials.filter((_, i) => i !== index));
    };

    const updateCommercial = (index: number, field: keyof Commercial, value: string) => {
        const newCommercials = [...commercials];
        newCommercials[index][field] = value;
        setCommercials(newCommercials);
    };

    const handleProvision = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);

        try {
            // 1. Create Organization
            const { data: org, error: orgError } = await supabase
                .from('organizations')
                .insert({ name: orgName })
                .select()
                .single();

            if (orgError) throw orgError;
            console.log('Organization created:', org.id);

            // 2. Create Admin Auth Account (this will fail if email already exists in Auth)
            // Note: In client-side, we use signUp.
            const { data: authData, error: signUpError } = await supabase.auth.signUp({
                email: adminEmail,
                password: adminPassword,
                options: {
                    data: {
                        full_name: adminName,
                        organization_id: org.id,
                        role: 'admin'
                    }
                }
            });

            if (signUpError) throw signUpError;
            const adminId = authData.user?.id;
            if (!adminId) throw new Error("Erreur de création de l'administrateur");

            // 3. Create Admin Profile in Public Schema
            const { error: profileError } = await supabase
                .from('profiles')
                .insert({
                    id: adminId,
                    organization_id: org.id,
                    full_name: adminName,
                    role: 'admin',
                    email: adminEmail,
                    is_active: true
                });

            if (profileError) throw profileError;

            // 4. Initialize Statuses for the Organization
            const { error: statusError } = await supabase.from('lead_statuses').insert([
                { id: 'nouveau', label: 'Nouveau', color: '#6366f1', is_default: true, sort_order: 1, organization_id: org.id },
                { id: 'contacte', label: 'Contacté', color: '#10b981', is_default: false, sort_order: 2, organization_id: org.id },
                { id: 'interesse', label: 'Intéressé', color: '#8b5cf6', is_default: false, sort_order: 3, organization_id: org.id },
                { id: 'inscrit', label: 'Inscrit', color: '#22c55e', is_default: false, sort_order: 4, organization_id: org.id },
                { id: 'perdu', label: 'Perdu', color: '#ef4444', is_default: false, sort_order: 5, organization_id: org.id }
            ]);

            if (statusError) throw statusError;

            // 5. Create Commercial Invitations or Profiles
            const validCommercials = commercials.filter(c => c.name.trim() && c.email.trim());
            if (validCommercials.length > 0) {
                const invitations = validCommercials.map(c => ({
                    organization_id: org.id,
                    email: c.email.trim(),
                    role: 'agent',
                    token: Math.random().toString(36).substring(2) + Date.now().toString(36),
                    invited_by: adminId,
                    status: 'pending'
                }));

                const { error: inviteError } = await supabase.from('invitations').insert(invitations);
                if (inviteError) throw inviteError;

                // Also create basic profiles for them so they show up in the agents list
                const profiles = validCommercials.map(c => ({
                    organization_id: org.id,
                    full_name: c.name.trim(),
                    role: 'agent',
                    email: c.email.trim(),
                    is_active: true
                }));
                const { error: commProfileError } = await supabase.from('profiles').insert(profiles);
                if (commProfileError) throw commProfileError;
            }

            setIsSuccess(true);
            addToast(`Organisation "${orgName}" créée avec succès !`, 'success');
        } catch (err: any) {
            console.error(err);
            addToast(err.message || "Erreur lors du provisionnement", "error");
        } finally {
            setIsLoading(false);
        }
    };

    if (isSuccess) {
        return (
            <div className="card" style={{ maxWidth: '600px', margin: '4rem auto', textAlign: 'center', padding: '3rem' }}>
                <div style={{ display: 'grid', placeItems: 'center', marginBottom: '1.5rem' }}>
                    <div style={{ width: '80px', height: '80px', borderRadius: '50%', background: 'rgba(34, 197, 94, 0.1)', display: 'grid', placeItems: 'center' }}>
                        <CheckCircle2 size={40} color="var(--success)" />
                    </div>
                </div>
                <h2 style={{ fontSize: '1.5rem', fontWeight: 800, marginBottom: '1rem' }}>Configuration terminée !</h2>
                <p style={{ color: 'var(--text-muted)', marginBottom: '2rem' }}>
                    L'organisation <strong>{orgName}</strong> et les comptes ont été créés.<br />
                    L'administrateur ({adminEmail}) peut maintenant se connecter.
                </p>
                <button
                    className="btn btn-primary"
                    style={{ width: '100%', justifyContent: 'center' }}
                    onClick={() => {
                        setIsSuccess(false);
                        setOrgName('');
                        setAdminName('');
                        setAdminEmail('');
                        setAdminPassword('');
                        setCommercials([{ name: '', email: '' }]);
                    }}
                >
                    Créer une autre organisation
                </button>
            </div>
        );
    }

    return (
        <div style={{ maxWidth: '800px', margin: '0 auto' }}>
            <div style={{ marginBottom: '2.5rem' }}>
                <h1 style={{ fontSize: '2rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                    <Sparkles className="text-secondary" /> Provisionnement Rapide
                </h1>
                <p style={{ color: 'var(--text-muted)' }}>Configurez une organisation complète et ses commerciaux en une seule étape.</p>
            </div>

            <form onSubmit={handleProvision} style={{ display: 'grid', gap: '2rem' }}>
                {/* Section Organisation */}
                <div className="card glass">
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1.5rem' }}>
                        <Building2 size={24} className="text-primary" />
                        <h3 style={{ fontSize: '1.25rem', fontWeight: 700 }}>Informations de l'Organisation</h3>
                    </div>
                    <div className="form-group">
                        <label>Nom de l'Organisation</label>
                        <input
                            type="text"
                            required
                            placeholder="ex: École Polytechnique"
                            value={orgName}
                            onChange={e => setOrgName(e.target.value)}
                            style={{ width: '100%', padding: '0.875rem', background: 'rgba(255,255,255,0.03)', border: '1px solid var(--border)', borderRadius: '8px', color: 'white' }}
                        />
                    </div>
                </div>

                {/* Section Administrateur */}
                <div className="card glass">
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1.5rem' }}>
                        <Lock size={24} className="text-warning" />
                        <h3 style={{ fontSize: '1.25rem', fontWeight: 700 }}>Compte Administrateur</h3>
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                        <div className="form-group">
                            <label>Nom Complet</label>
                            <input
                                type="text"
                                required
                                placeholder="Prénom Nom"
                                value={adminName}
                                onChange={e => setAdminName(e.target.value)}
                                style={{ width: '100%', padding: '0.875rem', background: 'rgba(255,255,255,0.03)', border: '1px solid var(--border)', borderRadius: '8px', color: 'white' }}
                            />
                        </div>
                        <div className="form-group">
                            <label>Email Admin</label>
                            <input
                                type="email"
                                required
                                placeholder="admin@ecole.com"
                                value={adminEmail}
                                onChange={e => setAdminEmail(e.target.value)}
                                style={{ width: '100%', padding: '0.875rem', background: 'rgba(255,255,255,0.03)', border: '1px solid var(--border)', borderRadius: '8px', color: 'white' }}
                            />
                        </div>
                    </div>
                    <div className="form-group" style={{ marginTop: '1rem' }}>
                        <label>Mot de passe temporaire</label>
                        <input
                            type="text"
                            required
                            placeholder="Min 6 caractères"
                            value={adminPassword}
                            onChange={e => setAdminPassword(e.target.value)}
                            style={{ width: '100%', padding: '0.875rem', background: 'rgba(255,255,255,0.03)', border: '1px solid var(--border)', borderRadius: '8px', color: 'white' }}
                        />
                    </div>
                </div>

                {/* Section Commerciaux */}
                <div className="card glass">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                            <Users size={24} className="text-secondary" />
                            <h3 style={{ fontSize: '1.25rem', fontWeight: 700 }}>Équipe de Commerciaux</h3>
                        </div>
                        <button
                            type="button"
                            onClick={addCommercial}
                            className="btn"
                            style={{ padding: '0.5rem 1rem', background: 'rgba(99, 102, 241, 0.1)', color: 'var(--primary)', border: 'none', borderRadius: '8px', display: 'flex', gap: '6px', fontSize: '0.875rem' }}
                        >
                            <Plus size={16} /> Ajouter
                        </button>
                    </div>

                    <div style={{ display: 'grid', gap: '1rem' }}>
                        {commercials.map((comm, index) => (
                            <div key={index} style={{ display: 'flex', gap: '1rem', alignItems: 'flex-end', background: 'rgba(255,255,255,0.01)', padding: '1rem', borderRadius: '10px' }}>
                                <div style={{ flex: 1 }}>
                                    <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Nom Complet</label>
                                    <input
                                        type="text"
                                        placeholder="Nom du commercial"
                                        value={comm.name}
                                        onChange={e => updateCommercial(index, 'name', e.target.value)}
                                        style={{ width: '100%', padding: '0.75rem', background: 'rgba(0,0,0,0.2)', border: '1px solid var(--border)', borderRadius: '6px', color: 'white' }}
                                    />
                                </div>
                                <div style={{ flex: 1 }}>
                                    <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Email</label>
                                    <input
                                        type="email"
                                        placeholder="email@commercial.com"
                                        value={comm.email}
                                        onChange={e => updateCommercial(index, 'email', e.target.value)}
                                        style={{ width: '100%', padding: '0.75rem', background: 'rgba(0,0,0,0.2)', border: '1px solid var(--border)', borderRadius: '6px', color: 'white' }}
                                    />
                                </div>
                                <button
                                    type="button"
                                    onClick={() => removeCommercial(index)}
                                    style={{ padding: '0.75rem', background: 'rgba(239, 68, 68, 0.1)', color: 'var(--danger)', border: 'none', borderRadius: '6px', cursor: 'pointer' }}
                                >
                                    <Trash size={18} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="card" style={{ background: 'rgba(245, 158, 11, 0.05)', border: '1px solid rgba(245, 158, 11, 0.2)', display: 'flex', gap: '1rem', padding: '1.25rem' }}>
                    <AlertCircle className="text-warning" style={{ flexShrink: 0 }} />
                    <p style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>
                        <strong>Note :</strong> L'administrateur pourra inviter officiellement les commerciaux pour qu'ils configurent leur mot de passe personnel. Les comptes commerciaux créés ici sont des pré-profils.
                    </p>
                </div>

                <button
                    type="submit"
                    disabled={isLoading}
                    className="btn btn-primary"
                    style={{ width: '100%', height: '56px', fontSize: '1.125rem', fontWeight: 700, justifyContent: 'center' }}
                >
                    {isLoading ? <><Loader2 className="spin" size={24} /> Configuration en cours...</> : 'LANCER LE PROVISIONNEMENT'}
                </button>
            </form>
        </div>
    );
};

