import React from 'react';
import { supabase } from '../supabaseClient';
import {
    LayoutDashboard,
    LayoutList,
    GraduationCap,
    Target,
    UserSquare2,
    Settings,
    LogOut
} from 'lucide-react';
import NotificationBell from './NotificationBell';

interface SidebarProps {
